SELECT ATT_FILE_NM, ATT_FILE_URL, LOCTN_CD, OLD_PRVSN_CD, PRDCT_ID, PRDCT_MK_CD, PRVSN_BTN_NM, PRVSN_CD, PRVSN_LONG_EXPLN, PRVSN_MK, PRVSN_NM, PRVSN_SHORT_EXPLN, REGIST_DT, REGIST_ID, SORT_ORD, UPD_DT, UPD_ID, USE_YN FROM ( SELECT ATT_FILE_NM, ATT_FILE_URL, LOCTN_CD, OLD_PRVSN_CD, PRDCT_ID, PRDCT_MK_CD, PRVSN_BTN_NM, PRVSN_CD, PRVSN_LONG_EXPLN, PRVSN_MK, PRVSN_NM, PRVSN_SHORT_EXPLN, REGIST_DT, REGIST_ID, SORT_ORD, UPD_DT, UPD_ID, USE_YN, ROW_NUMBER() OVER(PARTITION BY PRVSN_CD ORDER BY LOCTN_CD DESC) RN FROM MA30_PRDCT_PRVSN_MGT WHERE USE_YN = 'Y' AND LOCTN_CD IN
#{loctnCdItem}
AND PRVSN_CD = #{prvsnCd}
AND PRVSN_CD IN
#{prvsnCdItem}
) WHERE RN = 1 WITH UR
